#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) { return a > b ? a : b; }
int min(int a, int b) { return a < b ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int A[N], B[M];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < M; i++) {
            scanf("%d", &B[i]);
        }
        long long dp[N + 1][M + 1][2]; // 0 for max, 1 for min
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= M; j++) {
                dp[i][j][0] = -1;
                dp[i][j][1] = -1;
            }
        }
        for (int i = 0; i < N; i++) {
            dp[i][0][0] = 0;
            dp[i][0][1] = 0;
        }
        for (int j = 1; j <= M; j++) {
            for (int i = 0; i < N; i++) {
                if (j % 2 == 1) { // max
                    long long maxVal = -1;
                    for (int k = i; k < N; k++) {
                        if (k - i + 1 == B[j - 1]) {
                            long long sum = 0;
                            for (int l = i; l <= k; l++) {
                                sum += A[l];
                            }
                            if (dp[k + 1][j - 1][1] != -1) {
                                maxVal = max(maxVal, sum + dp[k + 1][j - 1][1]);
                            }
                        }
                    }
                    dp[i][j][0] = maxVal;
                } else { // min
                    long long minVal = 1e18;
                    for (int k = i; k < N; k++) {
                        if (k - i + 1 == B[j - 1]) {
                            long long sum = 0;
                            for (int l = i; l <= k; l++) {
                                sum += A[l];
                            }
                            if (dp[k + 1][j - 1][0] != -1) {
                                minVal = min(minVal, sum + dp[k + 1][j - 1][0]);
                            }
                        }
                    }
                    dp[i][j][1] = minVal;
                }
            }
        }
        printf("%lld\n", dp[0][M][0]);
    }
    return 0;
}

